create extension if not exists pgcrypto;
create type public.app_role as enum ('admin','docente');
create type public.student_status as enum ('activo','inactivo');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text not null check(length(full_name) between 3 and 160), role public.app_role not null default 'docente', active boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.students (id uuid primary key default gen_random_uuid(), document_number varchar(30) not null unique, first_names varchar(120) not null, last_names varchar(120) not null, email text, status public.student_status not null default 'activo', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.biometric_templates (id uuid primary key default gen_random_uuid(), student_id uuid not null unique references public.students(id) on delete cascade, descriptor_ciphertext text not null, descriptor_iv text not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.courses (id uuid primary key default gen_random_uuid(), name varchar(150) not null, code varchar(40) not null unique, active boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.attendance (id uuid primary key default gen_random_uuid(), student_id uuid not null references public.students(id), course_id uuid references public.courses(id) on delete set null, attendance_date date not null default (now() at time zone 'America/Lima')::date, entry_at timestamptz, exit_at timestamptz, match_distance numeric(8,6) not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), check(entry_at is not null), check(exit_at is null or exit_at >= entry_at));
create unique index attendance_one_daily_mark on public.attendance(student_id,attendance_date,coalesce(course_id,'00000000-0000-0000-0000-000000000000'::uuid));
create index attendance_student_date_idx on public.attendance(student_id,attendance_date desc);
create table public.audit_logs (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete set null, action text not null, entity text not null, entity_id uuid, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create index audit_created_idx on public.audit_logs(created_at desc);
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from profiles where id=auth.uid() and role='admin' and active)$$;
create or replace function public.is_staff() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from profiles where id=auth.uid() and active)$$;
alter table public.profiles enable row level security; alter table public.students enable row level security; alter table public.biometric_templates enable row level security; alter table public.courses enable row level security; alter table public.attendance enable row level security; alter table public.audit_logs enable row level security;
create policy "profile own or admin" on profiles for select to authenticated using(id=auth.uid() or is_admin()); create policy "profile admin manage" on profiles for all to authenticated using(is_admin()) with check(is_admin());
create policy "staff read students" on students for select to authenticated using(is_staff()); create policy "admin manages students" on students for all to authenticated using(is_admin()) with check(is_admin());
create policy "staff read courses" on courses for select to authenticated using(is_staff()); create policy "admin manages courses" on courses for all to authenticated using(is_admin()) with check(is_admin());
create policy "staff reads attendance" on attendance for select to authenticated using(is_staff()); create policy "admin manages attendance" on attendance for all to authenticated using(is_admin()) with check(is_admin()); create policy "admin reads audit" on audit_logs for select to authenticated using(is_admin());
-- No existen políticas para biometric_templates: sólo Edge Functions con service_role acceden a ellas.
create or replace function public.touch_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now(); return new; end$$;
create trigger profiles_touch before update on profiles for each row execute function touch_updated_at(); create trigger students_touch before update on students for each row execute function touch_updated_at(); create trigger courses_touch before update on courses for each row execute function touch_updated_at(); create trigger attendance_touch before update on attendance for each row execute function touch_updated_at();
